```powershell
# Analyser les détections Defender récentes

function Get-DefenderDetections {
    param([int]$DerniersJours = 7)

    try {
        $detections = Get-MpThreatDetection -ErrorAction Stop

        if ($detections) {
            $recentes = $detections | Where-Object { 
                $_.InitialDetectionTime -gt (Get-Date).AddDays(-$DerniersJours)
            }

            Write-Host "Détections Defender ($DerniersJours j) : $($recentes.Count)"

            $recentes | Sort-Object InitialDetectionTime -Descending |
                Select-Object -First 10 | ForEach-Object {
                $menace = Get-MpThreat -ThreatID $_.ThreatID -ErrorAction SilentlyContinue
                Write-Host ""
                Write-Host "  Menace      : $($menace.ThreatName)"
                Write-Host "  Catégorie   : $($menace.CategoryID)"
                Write-Host "  Sévérité    : $($menace.SeverityID)"
                Write-Host "  Détecté le  : $($_.InitialDetectionTime)"
                Write-Host "  Fichier     : $($_.Resources -join ',')"
                Write-Host "  Statut      : $($_.CurrentThreatExecutionStatusID)"
            }
        } else {
            Write-Host "Aucune détection récente"
        }
    } catch {
        Write-Host "Erreur : $_"
        Write-Host "(Defender non disponible ou droits insuffisants)"
    }
}

Get-DefenderDetections -DerniersJours 30

